from datetime import datetime
from collections import defaultdict


class InMemoryStorage:
    """内存存储

    用于存储：
    - 已处理的批次号（防重复提交）
    - 已处理的明细项ID（防重复处理）
    - 用户历史遗失记录
    - 设备历史遗失记录
    - 处理历史记录（用于历史回放）
    """

    def __init__(self):
        self._processed_batches: Dict[str, datetime] = {}
        self._processed_details: Dict[str, datetime] = {}
        self._user_loss_history: Dict[str, Dict] = defaultdict(lambda: {
            'count_90d': 0,
            'total_compensation': 0,
            'loss_records': []
        })
        self._device_loss_history: Dict[str, Dict] = defaultdict(lambda: {
            'last_loss_time': None,
            'loss_count': 0
        })
        self._user_blacklist: Set[str] = set()
        self._high_risk_models: Set[str] = set()
        self._high_risk_locations: Set[str] = set()
        self._process_history: List[Dict] = []
        self._batch_processing_status: Dict[str, str] = {}

    def is_batch_processed(self, batch_no: str) -> bool:
        """检查批次是否已处理"""
        return batch_no in self._processed_batches

    def mark_batch_processed(self, batch_no: str, status: str = 'COMPLETED'):
        """标记批次为已处理"""
        self._processed_batches[batch_no] = datetime.now()
        self._batch_processing_status[batch_no] = status

    def get_batch_status(self, batch_no: str) -> Optional[str]:
        """获取批次处理状态"""
        return self._batch_processing_status.get(batch_no)

    def get_batch_process_time(self, batch_no: str) -> Optional[datetime]:
        """获取批次处理时间"""
        return self._processed_batches.get(batch_no)

    def is_detail_processed(self, detail_id: str) -> bool:
        """检查明细项是否已处理"""
        return detail_id in self._processed_details

    def mark_detail_processed(self, detail_id: str):
        """标记明细项为已处理"""
        self._processed_details[detail_id] = datetime.now()

    def record_user_loss(self, user_id: str, loss_time: datetime, compensation_amount: float):
        """记录用户遗失记录"""
        history = self._user_loss_history[user_id]
        history['count_90d'] += 1
        history['total_compensation'] += compensation_amount or 0
        history['loss_records'].append({
            'loss_time': loss_time,
            'compensation_amount': compensation_amount
        })
        self._cleanup_old_user_records(user_id)

    def _cleanup_old_user_records(self, user_id: str):
        """清理超过90天的用户记录"""
        history = self._user_loss_history[user_id]
        now = datetime.now()
        recent_records = []
        count_90d = 0

        for record in history['loss_records']:
            days_diff = (now - record['loss_time']).days
            if days_diff <= 90:
                recent_records.append(record)
                count_90d += 1

        history['loss_records'] = recent_records
        history['count_90d'] = count_90d

    def record_device_loss(self, powerbank_sn: str, loss_time: datetime):
        """记录设备遗失记录"""
        history = self._device_loss_history[powerbank_sn]
        history['last_loss_time'] = loss_time
        history['loss_count'] += 1

    def get_user_history(self, user_id: str) -> Dict:
        """获取用户历史记录"""
        return self._user_loss_history.get(user_id, {
            'count_90d': 0,
            'total_compensation': 0,
            'loss_records': []
        })

    def get_device_history(self, powerbank_sn: str) -> Dict:
        """获取设备历史记录"""
        return self._device_loss_history.get(powerbank_sn, {
            'last_loss_time': None,
            'loss_count': 0
        })

    def add_to_blacklist(self, user_id: str):
        """添加用户到黑名单"""
        self._user_blacklist.add(user_id)

    def remove_from_blacklist(self, user_id: str):
        """从黑名单移除用户"""
        self._user_blacklist.discard(user_id)

    def is_user_blacklisted(self, user_id: str) -> bool:
        """检查用户是否在黑名单"""
        return user_id in self._user_blacklist

    def add_high_risk_model(self, model: str):
        """添加高风险设备型号"""
        self._high_risk_models.add(model)

    def remove_high_risk_model(self, model: str):
        """移除高风险设备型号"""
        self._high_risk_models.discard(model)

    def add_high_risk_location(self, location: str):
        """添加高风险地区"""
        self._high_risk_locations.add(location)

    def remove_high_risk_location(self, location: str):
        """移除高风险地区"""
        self._high_risk_locations.discard(location)

    def get_context_data(self) -> Dict:
        """获取规则引擎需要的上下文数据"""
        return {
            'user_loss_history': dict(self._user_loss_history),
            'device_loss_history': dict(self._device_loss_history),
            'user_blacklist': list(self._user_blacklist),
            'high_risk_models': list(self._high_risk_models),
            'high_risk_locations': list(self._high_risk_locations)
        }

    def record_process_history(self, trace_id: str, batch_no: str, request_data: Dict, response_data: Dict):
        """记录处理历史（用于历史回放）"""
        self._process_history.append({
            'trace_id': trace_id,
            'batch_no': batch_no,
            'request': request_data,
            'response': response_data,
            'process_time': datetime.now()
        })

    def get_process_history(self, batch_no: str = None, trace_id: str = None) -> List[Dict]:
        """查询处理历史"""
        results = self._process_history

        if batch_no:
            results = [h for h in results if h['batch_no'] == batch_no]

        if trace_id:
            results = [h for h in results if h['trace_id'] == trace_id]

        return sorted(results, key=lambda x: x['process_time'], reverse=True)

    def clear_all(self):
        """清空所有数据（用于测试）"""
        self._processed_batches.clear()
        self._processed_details.clear()
        self._user_loss_history.clear()
        self._device_loss_history.clear()
        self._user_blacklist.clear()
        self._high_risk_models.clear()
        self._high_risk_locations.clear()
        self._process_history.clear()
        self._batch_processing_status.clear()

    def get_statistics(self) -> Dict:
        """获取统计信息"""
        return {
            'processed_batches': len(self._processed_batches),
            'processed_details': len(self._processed_details),
            'users_with_history': len(self._user_loss_history),
            'devices_with_history': len(self._device_loss_history),
            'blacklist_users': len(self._user_blacklist),
            'high_risk_models': len(self._high_risk_models),
            'high_risk_locations': len(self._high_risk_locations),
            'process_history_records': len(self._process_history)
        }


storage = InMemoryStorage()
