from datetime import datetime, timedelta
import json

from app.models.schemas import (
    CompensationRequest, CompensationResponse,
    DetailItem, FailureDetail, SupplementInfo,
    ProcessStatus, FailureCategory, ProcessAction
)
from app.services.validator import DataValidator
from app.services.rule_engine import rule_engine
from app.services.storage import storage
from app.utils.trace_id_generator import TraceIdGenerator


class CompensationProcessor:
    """赔付业务处理器

    负责核心业务流程：
    1. 重复提交检测
    2. 数据校验
    3. 规则引擎检查
    4. 状态分流（可办理、需补充、已锁定、失败）
    5. 后续闭环处理
    """

    @classmethod
    def process(cls, request: CompensationRequest) -> CompensationResponse:
        """处理赔付请求

        Args:
            request: 赔付请求

        Returns:
            赔付响应
        """
        trace_id = TraceIdGenerator.generate(
            batch_no=request.batch_no,
            user_id=request.operator_id
        )

        try:
            response = cls._process_internal(request, trace_id)

            request_dict = json.loads(request.model_dump_json())
            response_dict = json.loads(response.model_dump_json())
            storage.record_process_history(trace_id, request.batch_no, request_dict, response_dict)

            return response

        except Exception as e:
            return CompensationResponse(
                trace_id=trace_id,
                batch_no=request.batch_no,
                process_status=ProcessStatus.FAILED,
                total_count=len(request.details),
                failed_count=len(request.details),
                failure_details=[
                    FailureDetail(
                        failure_category=FailureCategory.SYSTEM_ERROR,
                        failure_code="SYS_ERR_001",
                        failure_message=f"系统处理异常: {str(e)}",
                        suggestion="请联系技术支持或稍后重试"
                    )
                ]
            )

    @classmethod
    def _process_internal(
        cls,
        request: CompensationRequest,
        trace_id: str
    ) -> CompensationResponse:
        """内部处理逻辑"""

        total_count = len(request.details)
        processable_details: List[DetailItem] = []
        need_supplement_details: List[SupplementInfo] = []
        locked_details: List[DetailItem] = []
        all_failures: List[FailureDetail] = []

        if request.process_action != ProcessAction.SUPPLEMENT:
            duplicate_check_result = cls._check_duplicate_submit(request)
            if duplicate_check_result:
                return CompensationResponse(
                    trace_id=trace_id,
                    batch_no=request.batch_no,
                    process_status=ProcessStatus.FAILED,
                    total_count=total_count,
                    failed_count=total_count,
                    failure_details=[duplicate_check_result]
                )

        validation_failures = DataValidator.validate_request(request)
        if validation_failures:
            has_critical_errors = any(
                f.detail_id is None and f.failure_category == FailureCategory.VALIDATION_ERROR
                for f in validation_failures
            )

            if has_critical_errors:
                return CompensationResponse(
                    trace_id=trace_id,
                    batch_no=request.batch_no,
                    process_status=ProcessStatus.FAILED,
                    total_count=total_count,
                    failed_count=total_count,
                    failure_details=validation_failures
                )

        valid_detail_ids = {d.detail_id for d in request.details}
        validation_failures = [
            f for f in validation_failures
            if f.detail_id is None or f.detail_id in valid_detail_ids
        ]

        context = storage.get_context_data()
        context['source_channel'] = request.source_channel
        context['process_action'] = request.process_action
        context['review_opinion'] = request.review_opinion

        rule_results = rule_engine.check_details(request.details, context)

        for detail in request.details:
            detail_validation_failures = [
                f for f in validation_failures if f.detail_id == detail.detail_id
            ]

            if detail_validation_failures:
                all_failures.extend(detail_validation_failures)
                continue

            rule_result = rule_results.get(detail.detail_id, {})
            locked_rules = rule_result.get('locked_rules', [])
            review_rules = rule_result.get('review_rules', [])

            if locked_rules:
                all_failures.extend(locked_rules)
                locked_details.append(detail)
                continue

            missing_materials = DataValidator.check_missing_materials(detail)
            if missing_materials:
                supplement_deadline = datetime.now() + timedelta(days=DataValidator.MAX_SUPPLEMENT_DAYS)
                need_supplement_details.append(SupplementInfo(
                    detail_id=detail.detail_id,
                    missing_materials=missing_materials,
                    supplement_deadline=supplement_deadline
                ))
                continue

            if review_rules:
                all_failures.extend(review_rules)
                continue

            processable_details.append(detail)

        for detail in processable_details:
            storage.mark_detail_processed(detail.detail_id)
            comp_amount = detail.compensation_amount or detail.claim_amount
            storage.record_user_loss(detail.user_id, detail.loss_time, comp_amount)
            storage.record_device_loss(detail.powerbank_sn, detail.loss_time)

        if processable_details or locked_details or need_supplement_details:
            storage.mark_batch_processed(request.batch_no)

        process_status = cls._determine_process_status(
            processable_count=len(processable_details),
            need_supplement_count=len(need_supplement_details),
            locked_count=len(locked_details),
            failed_count=len(all_failures)
        )

        response = CompensationResponse(
            trace_id=trace_id,
            batch_no=request.batch_no,
            process_status=process_status,
            processable_count=len(processable_details),
            need_supplement_count=len(need_supplement_details),
            locked_count=len(locked_details),
            failed_count=len(all_failures),
            total_count=total_count,
            processable_details=processable_details,
            need_supplement_details=need_supplement_details,
            locked_details=locked_details,
            failure_details=all_failures
        )

        cls._add_remark(request, response)

        return response

    @classmethod
    def _check_duplicate_submit(cls, request: CompensationRequest) -> Optional[FailureDetail]:
        """检查重复提交"""

        if storage.is_batch_processed(request.batch_no):
            process_time = storage.get_batch_process_time(request.batch_no)
            batch_status = storage.get_batch_status(request.batch_no)

            time_str = process_time.strftime("%Y-%m-%d %H:%M:%S") if process_time else "未知"

            return FailureDetail(
                failure_category=FailureCategory.DUPLICATE_SUBMIT,
                failure_code="DUP_BAT_001",
                failure_message=f"批次号[{request.batch_no}]已在{time_str}处理过，当前状态: {batch_status}",
                suggestion="请勿重复提交同一批次，如需补充材料请使用SUPPLEMENT动作"
            )

        duplicate_details = []
        for detail in request.details:
            if storage.is_detail_processed(detail.detail_id):
                duplicate_details.append(detail.detail_id)

        if duplicate_details:
            return FailureDetail(
                failure_category=FailureCategory.DUPLICATE_SUBMIT,
                failure_code="DUP_DTL_001",
                failure_message=f"以下明细项ID已处理过: {', '.join(duplicate_details)}",
                suggestion="请检查明细项ID，请勿重复处理同一明细项"
            )

        return None

    @classmethod
    def _determine_process_status(
        cls,
        processable_count: int,
        need_supplement_count: int,
        locked_count: int,
        failed_count: int
    ) -> ProcessStatus:
        """确定整体处理状态"""

        if processable_count > 0 and need_supplement_count == 0 and locked_count == 0 and failed_count == 0:
            return ProcessStatus.PROCESSABLE

        if need_supplement_count > 0 and processable_count == 0 and locked_count == 0 and failed_count == need_supplement_count:
            return ProcessStatus.NEED_SUPPLEMENT

        if locked_count > 0 and processable_count == 0 and need_supplement_count == 0:
            return ProcessStatus.LOCKED

        if failed_count > 0 and processable_count == 0 and need_supplement_count == 0 and locked_count == 0:
            return ProcessStatus.FAILED

        if processable_count > 0:
            return ProcessStatus.PROCESSABLE

        if locked_count > 0:
            return ProcessStatus.LOCKED

        if need_supplement_count > 0:
            return ProcessStatus.NEED_SUPPLEMENT

        return ProcessStatus.FAILED

    @classmethod
    def _add_remark(cls, request: CompensationRequest, response: CompensationResponse):
        """添加备注信息"""
        remarks = []

        if request.review_opinion:
            remarks.append(f"复核意见: {request.review_opinion}")

        if request.operator_id:
            remarks.append(f"操作人: {request.operator_id}")

        if response.processable_count > 0:
            remarks.append(f"可办理{response.processable_count}项，将自动完成赔付流程")

        if response.need_supplement_count > 0:
            remarks.append(f"需补充{response.need_supplement_count}项，请在规定时间内补充材料")

        if response.locked_count > 0:
            remarks.append(f"已锁定{response.locked_count}项，需风控部门介入处理")

        if response.failed_count > 0:
            rule_hits = [f for f in response.failure_details if f.failure_category == FailureCategory.RULE_HIT]
            manual_reviews = [f for f in response.failure_details if f.failure_category == FailureCategory.MANUAL_REVIEW]
            duplicates = [f for f in response.failure_details if f.failure_category == FailureCategory.DUPLICATE_SUBMIT]
            validations = [f for f in response.failure_details if f.failure_category == FailureCategory.VALIDATION_ERROR]

            if rule_hits:
                remarks.append(f"规则命中{len(rule_hits)}项")
            if manual_reviews:
                remarks.append(f"需人工复核{len(manual_reviews)}项")
            if duplicates:
                remarks.append(f"重复提交{len(duplicates)}项")
            if validations:
                remarks.append(f"数据校验失败{len(validations)}项")

        if remarks:
            response.remark = "；".join(remarks)

    @classmethod
    def replay(cls, trace_id: str) -> Optional[Dict]:
        """历史回放

        Args:
            trace_id: 可追溯编号

        Returns:
            历史处理记录
        """
        history = storage.get_process_history(trace_id=trace_id)
        return history[0] if history else None

    @classmethod
    def get_history(cls, batch_no: str = None, trace_id: str = None) -> List[Dict]:
        """获取处理历史"""
        return storage.get_process_history(batch_no=batch_no, trace_id=trace_id)


processor = CompensationProcessor()
