from fastapi import FastAPI, HTTPException, Query
from fastapi.middleware.cors import CORSMiddleware

from app.models.schemas import (
    CompensationRequest, CompensationResponse,
    ProcessStatus, FailureCategory
)
from app.services.processor import processor
from app.services.rule_engine import rule_engine
from app.services.storage import storage
from app.utils.trace_id_generator import TraceIdGenerator

app = FastAPI(
    title="共享充电宝遗失赔付API",
    description="围绕业务人员围绕共享充电宝遗失赔付完成数据校验、状态分流和后续闭环设计接口",
    version="1.0.0"
)

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)


@app.get("/", tags=["健康检查"])
async def root():
    """根路径，健康检查"""
    return {
        "status": "ok",
        "service": "共享充电宝遗失赔付API",
        "version": "1.0.0",
        "trace_id_example": TraceIdGenerator.generate()
    }


@app.get("/health", tags=["健康检查"])
async def health_check():
    """健康检查"""
    stats = storage.get_statistics()
    return {
        "status": "healthy",
        "statistics": stats
    }


@app.post("/api/compensation/process", response_model=CompensationResponse, tags=["赔付处理"])
async def process_compensation(request: CompensationRequest):
    """处理共享充电宝遗失赔付请求

    接收批次号、明细项、来源渠道、处理动作和复核意见，返回可办理、需补充、已锁定和失败解释。

    - **规则命中**：自动检测业务规则并返回具体命中的规则信息
    - **人工复核**：对于需要人工介入的申请，明确标注并给出处理建议
    - **重复提交**：检测重复批次和重复明细项，防止重复处理
    """
    try:
        response = processor.process(request)
        return response
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"服务端错误: {str(e)}")


@app.get("/api/compensation/replay/{trace_id}", tags=["历史回放"])
async def replay_compensation(trace_id: str):
    """根据可追溯编号回放历史处理记录

    用于查询历史处理结果，支持问题排查和审计追溯。
    """
    result = processor.replay(trace_id)
    if not result:
        raise HTTPException(status_code=404, detail=f"未找到追溯编号为{trace_id}的处理记录")
    return result


@app.get("/api/compensation/history", tags=["历史查询"])
async def get_compensation_history(
    batch_no: Optional[str] = Query(None, description="批次号"),
    trace_id: Optional[str] = Query(None, description="可追溯编号")
):
    """查询赔付处理历史

    支持按批次号或追溯编号查询处理历史记录。
    """
    if not batch_no and not trace_id:
        raise HTTPException(status_code=400, detail="请至少提供batch_no或trace_id中的一个参数")

    history = processor.get_history(batch_no=batch_no, trace_id=trace_id)
    return {
        "count": len(history),
        "records": history
    }


@app.get("/api/rules", tags=["规则管理"])
async def get_all_rules():
    """获取所有业务规则"""
    return {
        "rules": rule_engine.get_all_rules()
    }


@app.post("/api/rules/{rule_id}/enable", tags=["规则管理"])
async def enable_rule(rule_id: str):
    """启用指定规则"""
    rule_engine.enable_rule(rule_id)
    return {"status": "success", "message": f"规则{rule_id}已启用"}


@app.post("/api/rules/{rule_id}/disable", tags=["规则管理"])
async def disable_rule(rule_id: str):
    """禁用指定规则"""
    rule_engine.disable_rule(rule_id)
    return {"status": "success", "message": f"规则{rule_id}已禁用"}


@app.get("/api/status/definitions", tags=["状态定义"])
async def get_status_definitions():
    """获取所有状态和错误码定义"""
    return {
        "process_status": {
            s.name: s.value for s in ProcessStatus
        },
        "failure_category": {
            c.name: c.value for c in FailureCategory
        },
        "status_explanations": {
            "PROCESSABLE": "可办理：所有校验通过，可以正常办理赔付",
            "NEED_SUPPLEMENT": "需补充：材料不完整，需要补充后再办理",
            "LOCKED": "已锁定：命中风控规则，需人工介入审核",
            "FAILED": "失败：请求校验不通过或命中拒绝规则"
        },
        "failure_category_explanations": {
            "RULE_HIT": "规则命中：自动拒绝类规则，不予赔付",
            "MANUAL_REVIEW": "人工复核：需人工审核类规则，待审核",
            "DUPLICATE_SUBMIT": "重复提交：批次或明细项已处理过",
            "VALIDATION_ERROR": "校验错误：参数不合法",
            "SYSTEM_ERROR": "系统错误：服务端异常"
        }
    }


